// W_Regen Get Params — extracts the lesson_id from rows flagged needs_retts=TRUE,
// then prepends a sentinel item carrying lesson_id so downstream Build Full / VTT can read
// $('Get Params').first().json.lesson_id (the W3 contract). Other items pass through unchanged;
// Regen Engine filters them by needs_retts so the sentinel is harmless.
// MVP constraint: single-lesson regen per run.
const allRows = $input.all();
const flagged = allRows.filter(it => {
  const v = it.json.needs_retts;
  return v === true || v === 'TRUE' || v === 'true';
});
if (flagged.length === 0) {
  throw new Error('W_Regen: no rows flagged needs_retts=TRUE — set the flag on at least one row before running.');
}
const lessonIds = [...new Set(flagged.map(it => it.json.lesson_id || (it.json.segment_id || '').split('_seg_')[0]))].filter(Boolean);
if (lessonIds.length > 1) {
  throw new Error(`W_Regen MVP supports a single lesson per run; flagged rows span: ${lessonIds.join(', ')}. Clear the flag on all but one lesson and re-run.`);
}
const lesson_id = lessonIds[0];
console.log(`W_Regen Get Params: lesson_id=${lesson_id}, flagged_count=${flagged.length}`);
// Sentinel first, then all rows. Build Full / VTT will read .first().json.lesson_id.
return [{ json: { lesson_id, _sentinel: true } }, ...allRows];

// W_Regen — Regen Engine Code node.
// Reads localizations rows from upstream Read Localizations, filters where
// needs_retts=TRUE, and synthesizes each via ElevenLabs using Phase 1-style
// timing logic (lead silence + speech + tail silence to match phase1_final_duration).
//
// Editor flow:
//   1. Open localizations sheet, find row(s) to fix.
//   2. Edit text_translated (and any other content fields if needed).
//   3. Set needs_retts=TRUE; optionally add regen_comment for audit.
//   4. Trigger W_Regen via Manual Trigger.
// Result: audio for each flagged cell overwritten in Drive, sheet metrics updated,
// needs_retts cleared, last_regen_at set.
//
// Multi-cell + multi-lesson handled in one run: cells processed with bounded concurrency
// (regen_concurrency config key, default 5). Affected lessons are deduped and propagated
// downstream so Build Full Audio + VTT regenerates only the lessons that had at least
// one cell touched.

const SAMPLE_RATE = 44100;
const BPS = 2;
const MIN_VALID_PCM_BYTES = 8820;
const NEEDS_ATTENTION_THRESHOLD = 0.70;

const configMap = {};
$('Read Config').all().forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });

const voiceMap = {};
$('Read Voices').all().forEach(i => { if (i.json.lang) voiceMap[i.json.lang] = i.json; });

const EL_KEY = configMap.elevenlabs_api_key || '';
if (!EL_KEY) throw new Error('elevenlabs_api_key missing from config sheet');

const MAX_SPEED_UP_DELTA = parseFloat(configMap.max_speed_up_delta) || 0.20;
const MAX_SLOW_DOWN_DELTA = parseFloat(configMap.max_slow_down_delta) || 0.15;
const SLOWDOWN_MIN_GAP_SEC = parseFloat(configMap.slowdown_min_gap_sec) || 0.5;
const REGEN_CONCURRENCY = parseFloat(configMap.regen_concurrency) || 5;

// Read upstream localizations rows, filter by needs_retts flag
const allRows = $input.all();
const candidates = allRows.filter(it => {
  const v = it.json.needs_retts;
  return v === true || v === 'TRUE' || v === 'true';
});

if (candidates.length === 0) {
  console.log('W_Regen: no rows flagged needs_retts=TRUE — exiting cleanly (no Slack notification, no sheet writes).');
  // Return [] so downstream nodes (Has Audio?, Update Localizations Row, Build Full,
  // Wait For Saves, Slack Notify) simply don't fire. Workflow ends with success.
  // This makes spurious triggers (Slack link unfurl, accidental webhook GET) harmless.
  return [];
}

console.log(`W_Regen: ${candidates.length} cells flagged for regeneration`);

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

function buildWav(pcm) {
  const n = pcm.length;
  const h = Buffer.alloc(44);
  h.write('RIFF', 0); h.writeUInt32LE(36 + n, 4); h.write('WAVE', 8); h.write('fmt ', 12);
  h.writeUInt32LE(16, 16); h.writeUInt16LE(1, 20); h.writeUInt16LE(1, 22); h.writeUInt32LE(SAMPLE_RATE, 24);
  h.writeUInt32LE(SAMPLE_RATE * BPS, 28); h.writeUInt16LE(BPS, 32); h.writeUInt16LE(16, 34);
  h.write('data', 36); h.writeUInt32LE(n, 40);
  return Buffer.concat([h, pcm]);
}

async function synthOne(row) {
  const j = row.json;
  const lang = j.lang;
  const voice = voiceMap[lang];
  if (!voice || !voice.voice_id) {
    return {
      json: { ...j, regen_error: `no voice for lang=${lang}`, has_audio: false },
    };
  }

  const text = (j.text_translated || '').toString();
  if (!text.trim()) {
    return {
      json: { ...j, regen_error: 'text_translated is empty', has_audio: false },
    };
  }

  const enDur = parseFloat(j.en_duration_sec) || 0;
  const lead = parseFloat(j.lead_silence_sec) || 0;
  // Target the EXACT slot duration Phase 1 produced — matches Phase 2 reTtsOne logic
  // so the concatenated full WAV stays EN-aligned after regen.
  const phase1FinalDur = parseFloat(j.final_duration_sec) || 0;
  const targetFileDur = phase1FinalDur > 0 ? phase1FinalDur : (lead + enDur);
  const speechBudget = targetFileDur - lead;

  if (speechBudget <= 0) {
    return {
      json: { ...j, regen_error: `speechBudget <= 0 (lead=${lead}, target=${targetFileDur})`, has_audio: false },
    };
  }

  const baseSpeed = parseFloat(voice.speed) || 1.0;
  const stability = parseFloat(voice.stability) || 0.5;
  const similarity = parseFloat(voice.similarity_boost) || 0.75;
  const style = parseFloat(voice.style) || 0;
  const model = voice.model || 'eleven_multilingual_v2';

  async function ttsAt(speed) {
    const MAX_TRIES = 4;
    for (let attempt = 0; attempt < MAX_TRIES; attempt++) {
      try {
        const resp = await this.helpers.httpRequest({
          method: 'POST',
          url: `https://api.elevenlabs.io/v1/text-to-speech/${voice.voice_id}/stream?output_format=pcm_44100`,
          headers: { 'xi-api-key': EL_KEY, 'content-type': 'application/json', accept: 'audio/pcm' },
          body: {
            text,
            model_id: model,
            voice_settings: { stability, similarity_boost: similarity, style, speed },
          },
          encoding: 'arraybuffer',
          returnFullResponse: false,
        });
        return Buffer.from(resp);
      } catch (e) {
        if (attempt === MAX_TRIES - 1) {
          console.error(`W_Regen TTS failed for ${j.segment_id}_${lang}:`, e.message);
          return null;
        }
        await sleep(2000 * Math.pow(2, attempt));
      }
    }
    return null;
  }

  let pcm = await ttsAt.call(this, baseSpeed);
  if (!pcm || pcm.length < MIN_VALID_PCM_BYTES) {
    return {
      json: { ...j, regen_error: 'TTS produced no audio', has_audio: false },
    };
  }
  let real = pcm.length / (SAMPLE_RATE * BPS);
  let usedSpeed = baseSpeed;

  // Speed-up retry if overshoot (mirrors Phase 1 shorten path + Phase 2 reTtsOne)
  if (real > speechBudget) {
    const steps = [
      baseSpeed + MAX_SPEED_UP_DELTA * (2 / 3),
      baseSpeed + MAX_SPEED_UP_DELTA,
    ];
    for (const speedTry of steps) {
      const fastPcm = await ttsAt.call(this, speedTry);
      if (!fastPcm || fastPcm.length < MIN_VALID_PCM_BYTES) continue;
      const fastReal = fastPcm.length / (SAMPLE_RATE * BPS);
      if (fastReal <= speechBudget) {
        pcm = fastPcm; real = fastReal; usedSpeed = parseFloat(speedTry.toFixed(3));
        break;
      }
    }
  }

  let needsAttention = false;

  if (real > speechBudget) {
    // Still overshoot at max speed-up — hard-truncate and flag
    needsAttention = true;
    const truncBytes = Math.round(speechBudget * SAMPLE_RATE) * BPS;
    pcm = pcm.subarray(0, truncBytes);
    real = pcm.length / (SAMPLE_RATE * BPS);
  } else if (speechBudget - real > SLOWDOWN_MIN_GAP_SEC) {
    // Slowdown-to-fill (mirrors Phase 2 reTtsOne)
    const floor = baseSpeed - MAX_SLOW_DOWN_DELTA;
    const wanted = baseSpeed * (real / speechBudget);
    const slowSpeed = parseFloat(Math.max(floor, wanted).toFixed(3));
    if (slowSpeed < baseSpeed - 1e-6 && slowSpeed > 0) {
      const slowPcm = await ttsAt.call(this, slowSpeed);
      if (slowPcm && slowPcm.length >= MIN_VALID_PCM_BYTES) {
        const slowReal = slowPcm.length / (SAMPLE_RATE * BPS);
        if (slowReal <= speechBudget) {
          pcm = slowPcm; real = slowReal; usedSpeed = slowSpeed;
        }
      }
    }
  }

  const tail = Math.max(0, targetFileDur - lead - real);

  // Flag if speech is significantly shorter than the EN slot (mirrors Phase 2 threshold)
  if (enDur > 0 && real / enDur < NEEDS_ATTENTION_THRESHOLD) needsAttention = true;

  const leadBytes = Math.round(lead * SAMPLE_RATE) * BPS;
  const tailBytes = Math.round(tail * SAMPLE_RATE) * BPS;
  const fullPcm = Buffer.concat([
    leadBytes > 0 ? Buffer.alloc(leadBytes, 0) : Buffer.alloc(0),
    pcm,
    tailBytes > 0 ? Buffer.alloc(tailBytes, 0) : Buffer.alloc(0),
  ]);
  const wav = buildWav(fullPcm);
  const finalDur = (leadBytes + pcm.length + tailBytes) / (SAMPLE_RATE * BPS);

  return {
    json: {
      row_key:                       j.row_key,
      segment_id:                    j.segment_id,
      lang,
      lesson_id:                     j.lesson_id || (j.segment_id || '').split('_seg_')[0],
      text_translated:               text,
      en_start_sec:                  parseFloat(j.en_start_sec) || 0,
      en_duration_sec:               enDur,
      slot_start_sec:                parseFloat(j.slot_start_sec) || 0,
      slot_end_sec:                  parseFloat(j.slot_end_sec) || 0,
      lead_silence_sec:              parseFloat(lead.toFixed(3)),
      tts_budget_sec:                parseFloat(j.tts_budget_sec) || enDur,
      tail_silence_sec:              parseFloat(tail.toFixed(3)),
      real_duration_sec:             parseFloat(real.toFixed(3)),
      final_duration_sec:            parseFloat(finalDur.toFixed(3)),
      borrowed_sec:                  parseFloat(j.borrowed_sec) || 0,
      expansion_attempts:            parseFloat(j.expansion_attempts) || 0,
      shorten_retries_in_synthesize: parseFloat(j.shorten_retries_in_synthesize) || 0,
      final_speed:                   usedSpeed,
      // Tri-state needs_attention semantics:
      //   TRUE  = W_Regen still couldn't fit audio in slot (hard-truncated or speech <70%)
      //   REVIEW = W_Regen produced a valid file — human should listen + flip to FALSE/TRUE
      //   FALSE = (only W3 writes this; W_Regen never demotes to FALSE — human verifies)
      // Operator workflow: W3 writes TRUE/FALSE → operator flags TRUE → runs W_Regen →
      // cell becomes REVIEW (yellow) → operator listens → manually flips to FALSE (green)
      // or back to TRUE (red) if regen still sounds wrong.
      needs_attention:               needsAttention ? 'TRUE' : 'REVIEW',
      needs_retts:                   'FALSE',
      // Kyiv local time, Sheets-friendly format "YYYY-MM-DD HH:MM:SS".
      // 'sv-SE' locale uses ISO-like format with space separator, ideal for sorting.
      last_regen_at:                 new Date().toLocaleString('sv-SE', { timeZone: 'Europe/Kyiv' }),
      regen_comment:                 j.regen_comment || '',
      audio_drive_file_id:           j.audio_drive_file_id,
      phase2_outcome:                j.phase2_outcome || '',
      file_name:                     `${j.segment_id}_${lang}.wav`,
      has_audio:                     true,
    },
    binary: {
      data: {
        data:     wav.toString('base64'),
        mimeType: 'audio/wav',
        fileName: `${j.segment_id}_${lang}.wav`,
      },
    },
  };
}

// Bounded-concurrent synthesis. Same idiom as W3 Phase 2 reTtsOne batching.
const results = [];
for (let i = 0; i < candidates.length; i += REGEN_CONCURRENCY) {
  const slice = candidates.slice(i, i + REGEN_CONCURRENCY);
  const partial = await Promise.all(slice.map(c => synthOne.call(this, c)));
  for (const r of partial) results.push(r);
}

const ok = results.filter(r => r.json.has_audio).length;
const failed = results.length - ok;
const affectedLessons = [...new Set(results.filter(r => r.json.has_audio).map(r => r.json.lesson_id))];
console.log(`W_Regen: ${ok} cells regenerated, ${failed} failed, affected lessons: ${affectedLessons.join(', ')}`);

return results;

// Concat per-segment WAVs into one full WAV per language.
// Memory-conscious: iterates active_langs sequentially, no pre-grouping of all items,
// explicit reference cleanup after each lang. Pairs with N8N_BINARY_DATA_MODE=filesystem
// for further heap savings.
const SAMPLE_RATE = 44100;
const BPS         = 2;

const lesson_id = $('Get Params').first().json.lesson_id;

const configMap = {};
$('Read Config').all().forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
// Per-lang dispatch (B2): scope to the single lang the orchestrator passed (via Get
// Params active_langs); absent → config (all langs). Keeps peak memory at ~1 lang.
const langOverride = $('Get Params').first().json.active_langs;
const activeLangs = (langOverride || configMap.active_langs || 'de,es,fr,it,pl,pt,tr')
  .split(',').map(s => s.trim()).filter(Boolean).sort();

// As of 2026-05-31 refactor: borrow compensation is now done UPSTREAM by the
// new `Trim Lead For Sequence` node (which trims each post-borrow segment's
// lead silence by the previous segment's borrowed_sec and overwrites the Drive
// copy via a parallel Save Trimmed Audio path). By the time items reach Build
// Full Audio Per Lang, they are already sequence-aligned. This node is now a
// pure concatenator — just strip 44-byte WAV headers, accumulate PCM, emit.
//
// Why the change: individual WAVs in Drive used to extend past their slot_end
// for short-segment-borrow cells; editors placing them end-to-end (e.g. in
// Reaper) saw ~1.5s cumulative drift. Trimming upstream gives Drive a
// sequence-friendly set of files; Build Full Audio no longer needs special
// per-segment compensation logic.

const items = $input.all();
if (!items.length) throw new Error('No items — Download Segment WAV must run first');

// Map item reference → its original index in $input.all() so that, after
// filter/sort, we can still pass the correct itemIndex to getBinaryDataBuffer.
// (Critical for N8N_BINARY_DATA_MODE=filesystem support — see Check Timing + Pad.)
const indexMap = new Map(items.map((it, idx) => [it, idx]));

const results = [];
for (const lang of activeLangs) {
  // Lazy filter for current lang only (no pre-grouping → no doubled refs).
  const entries = items
    .filter(i => i.json && i.json.lang === lang)
    .filter(i => !lesson_id || (i.json.segment_id || '').startsWith(lesson_id + '_'))
    .sort((a, b) => String(a.json.segment_id).localeCompare(String(b.json.segment_id)));

  if (!entries.length) continue;

  // Strip 44-byte WAV header from each segment, accumulate raw PCM.
  // Segments come in already trimmed by upstream Trim Lead For Sequence node, so
  // this is a straight concat — no per-segment borrow compensation here.
  const pcmChunks = [];
  let skippedNoBinary = 0;
  let skippedEmptyWav = 0;
  for (const e of entries) {
    if (!e.binary?.data) {
      skippedNoBinary++;
      console.warn(`Build Full: ${lang} ${e.json?.segment_id} skipped — no binary slot on item`);
      continue;
    }
    // CRITICAL: must use this.helpers.getBinaryDataBuffer() — with
    // N8N_BINARY_DATA_MODE=filesystem the raw binary.data.data is a tiny
    // placeholder, not the actual WAV bytes.
    const originalIdx = indexMap.get(e);
    if (originalIdx === undefined) {
      skippedNoBinary++;
      console.warn(`Build Full: ${lang} ${e.json?.segment_id} skipped — could not resolve original item index`);
      continue;
    }
    let wavBuf;
    try {
      wavBuf = await this.helpers.getBinaryDataBuffer(originalIdx, 'data');
    } catch (err) {
      skippedNoBinary++;
      console.warn(`Build Full: ${lang} ${e.json?.segment_id} skipped — getBinaryDataBuffer failed: ${err.message}`);
      continue;
    }
    if (!wavBuf || wavBuf.length <= 44) {
      skippedEmptyWav++;
      console.warn(`Build Full: ${lang} ${e.json?.segment_id} skipped — WAV is ${wavBuf?.length ?? 0} bytes (header-only or empty)`);
      continue;
    }
    pcmChunks.push(wavBuf.subarray(44));
  }

  const fullPcm = Buffer.concat(pcmChunks);
  pcmChunks.length = 0;  // explicit ref clear — helps GC reclaim per-segment buffers
  const n = fullPcm.length;

  // Build fresh WAV header (44100Hz mono 16-bit — matches segments)
  const h = Buffer.alloc(44);
  h.write('RIFF', 0);          h.writeUInt32LE(36 + n, 4);
  h.write('WAVE', 8);          h.write('fmt ', 12);
  h.writeUInt32LE(16, 16);     h.writeUInt16LE(1, 20);
  h.writeUInt16LE(1, 22);      h.writeUInt32LE(SAMPLE_RATE, 24);
  h.writeUInt32LE(SAMPLE_RATE * BPS, 28);
  h.writeUInt16LE(BPS, 32);    h.writeUInt16LE(16, 34);
  h.write('data', 36);         h.writeUInt32LE(n, 40);
  const fullWav = Buffer.concat([h, fullPcm]);

  const lessonId = String(entries[0].json.segment_id).split('_seg_')[0] || 'lesson';
  const fileName = `${lessonId}_full_${lang}.wav`;

  if (skippedNoBinary > 0 || skippedEmptyWav > 0) {
    console.warn(`Build Full: ${lang} skipped ${skippedNoBinary} items (no binary) + ${skippedEmptyWav} items (empty WAV) out of ${entries.length}`);
  }
  results.push({
    json: {
      lang,
      lesson_id:              lessonId,
      file_name:              fileName,
      total_segments:         entries.length,
      skipped_no_binary:      skippedNoBinary,
      skipped_empty_wav:      skippedEmptyWav,
      full_duration_sec:      parseFloat((n / (SAMPLE_RATE * BPS)).toFixed(3)),
    },
    binary: {
      data: {
        data:     fullWav.toString('base64'),
        mimeType: 'audio/wav',
        fileName,
      },
    },
  });
  // fullPcm + fullWav fall out of scope at next iteration — GC can reclaim.
}

if (!results.length) throw new Error('No localizations to concat' + (lesson_id ? ' for lesson_id=' + lesson_id : ''));
return results;

// Build WebVTT subtitles per active language. One .vtt per lang, matching the
// full-lesson WAV positions. Runs in parallel with Download Segment WAV (both read
// the same Read Localizations Fresh output).
//
// Cue timings: en_start_sec → en_end_sec. After the borrow-compensation fix in
// Build Full Audio Per Lang, each segment in the full WAV starts exactly at
// en_start_sec — so EN-aligned cues match the dubbed audio for every language.
// Cue text: text_translated (final version after Verify + Adapt + W3 shorten).

const lesson_id = $('Get Params').first().json.lesson_id;

const configMap = {};
$('Read Config').all().forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
// Per-lang dispatch (B2): scope to the single lang the orchestrator passed (via Get
// Params active_langs); absent → config (all langs).
const langOverride = $('Get Params').first().json.active_langs;
const activeLangs = (langOverride || configMap.active_langs || 'de,es,fr,it,pl,pt,tr')
  .split(',').map(s => s.trim()).filter(Boolean);

const items = $input.all();
if (!items.length) throw new Error('No items — Read Localizations Fresh must run first');

function fmtTime(sec) {
  // VTT timestamp: HH:MM:SS.mmm
  const h = Math.floor(sec / 3600);
  const m = Math.floor((sec % 3600) / 60);
  const s = sec - h * 3600 - m * 60;
  return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}:${s.toFixed(3).padStart(6, '0')}`;
}

const results = [];
for (const lang of activeLangs) {
  const segs = items
    .filter(i => i.json && i.json.lang === lang)
    .filter(i => !lesson_id || (i.json.segment_id || '').startsWith(lesson_id + '_'))
    .sort((a, b) => String(a.json.segment_id).localeCompare(String(b.json.segment_id)));
  if (!segs.length) continue;

  const lines = ['WEBVTT', ''];
  let cueIdx = 0;
  for (const e of segs) {
    const s = e.json;
    const start = parseFloat(s.en_start_sec) || 0;
    const dur   = parseFloat(s.en_duration_sec) || 0;
    const end   = start + dur;
    const text  = (s.text_translated || '').toString().trim().replace(/\r?\n/g, ' ');
    if (!text) continue;
    cueIdx++;
    lines.push(String(cueIdx));
    lines.push(`${fmtTime(start)} --> ${fmtTime(end)}`);
    lines.push(text);
    lines.push('');
  }
  if (cueIdx === 0) continue;
  const vtt = lines.join('\n');

  const lessonId = String(segs[0].json.segment_id).split('_seg_')[0] || 'lesson';
  const fileName = `${lessonId}_full_${lang}.vtt`;
  results.push({
    json: {
      lang,
      lesson_id: lessonId,
      file_name: fileName,
      total_cues: cueIdx,
      vtt_bytes:  Buffer.byteLength(vtt, 'utf8'),
    },
    binary: {
      data: {
        data: Buffer.from(vtt, 'utf8').toString('base64'),
        mimeType: 'text/vtt',
        fileName,
      },
    },
  });
}

if (!results.length) throw new Error('No localizations for VTT' + (lesson_id ? ' for lesson_id=' + lesson_id : ''));
return results;

// Coalesce — collapses N Update Localizations Row output items into 1 trigger item.
// Reason: downstream Read Localizations Fresh fires per-input-item by default. With 3
// regen'd cells we'd get 3 sheet reads, each emitting 3xN items downstream — Build Full
// would then concat each segment 3 times. Coalescing to 1 item ensures Read Loc Fresh
// fires exactly once, returning the clean N-row localizations set.
const items = $input.all();
console.log(`W_Regen Coalesce: ${items.length} updates complete, triggering single-fire downstream`);
return [{ json: { updates_count: items.length, _trigger: true } }];

// Plan Old Deletes Full — extract file IDs of duplicate files to delete.
// Input: search responses (one per lang) with .files[] arrays.
// Read just-saved file IDs from $('Save Full to Drive').all() and exclude them.
const items = $input.all();
const savedItems = $('Save Full to Drive').all();
const newIds = new Set(savedItems.map(i => i.json.id).filter(Boolean));
console.log(`Plan Old Deletes Full: just-saved IDs to preserve: ${[...newIds].join(', ')}`);
const out = [];
let totalFound = 0, totalOld = 0;
for (const item of items) {
  const files = item.json.files || [];
  totalFound += files.length;
  for (const f of files) {
    if (!newIds.has(f.id)) {
      totalOld++;
      out.push({ json: { file_id: f.id, file_name: f.name } });
    }
  }
}
console.log(`Plan Old Deletes Full: search returned ${totalFound} matches total, ${totalOld} old (to delete), ${totalFound - totalOld} kept (just-uploaded)`);
return out;

// Plan Old Deletes VTT — extract file IDs of duplicate files to delete.
// Input: search responses (one per lang) with .files[] arrays.
// Read just-saved file IDs from $('Save VTT to Drive').all() and exclude them.
const items = $input.all();
const savedItems = $('Save VTT to Drive').all();
const newIds = new Set(savedItems.map(i => i.json.id).filter(Boolean));
console.log(`Plan Old Deletes VTT: just-saved IDs to preserve: ${[...newIds].join(', ')}`);
const out = [];
let totalFound = 0, totalOld = 0;
for (const item of items) {
  const files = item.json.files || [];
  totalFound += files.length;
  for (const f of files) {
    if (!newIds.has(f.id)) {
      totalOld++;
      out.push({ json: { file_id: f.id, file_name: f.name } });
    }
  }
}
console.log(`Plan Old Deletes VTT: search returned ${totalFound} matches total, ${totalOld} old (to delete), ${totalFound - totalOld} kept (just-uploaded)`);
return out;

// Build one Slack message per affected lesson after a W_Regen run.
// Symmetric to W_Master's Build Slack Message: emits { channel, text }.
// Reads:
//   $('Read Config').all()              — slack_channel, folder IDs, w_regen_workflow_url
//   $('Regen Engine').all()             — per-cell results (has_audio, lesson_id, regen_error)
//   $('Read Localizations Fresh').all() — post-regen rows for needs_attention rate
// Fires only when at least one cell was regenerated; empty runs short-circuit.
const cfg = {};
$('Read Config').all().forEach(i => { if (i.json && i.json.key) cfg[i.json.key] = i.json.value; });

const channel = cfg.slack_channel;
if (!channel) {
  console.log('W_Regen Slack: slack_channel missing — skipping notification');
  return [];
}

const fullFolder = cfg.drive_output_full_folder_id || cfg.drive_output_folder_id;
const segmentsFolder = cfg.drive_output_folder_id;
const vttFolder  = cfg.drive_output_vtt_folder_id;
const regenUrl   = cfg.w_regen_workflow_url;
const fullUrl     = fullFolder     ? `https://drive.google.com/drive/folders/${fullFolder}`     : null;
const segmentsUrl = segmentsFolder ? `https://drive.google.com/drive/folders/${segmentsFolder}` : null;
const vttUrl      = vttFolder      ? `https://drive.google.com/drive/folders/${vttFolder}`      : null;

const regenResults = $('Regen Engine').all().map(i => i.json || {});
const lessonStats = new Map();
for (const r of regenResults) {
  if (!r.lesson_id) continue;
  const s = lessonStats.get(r.lesson_id) || { ok: 0, failed: 0 };
  if (r.has_audio) s.ok++;
  else if (r.regen_error) s.failed++;
  lessonStats.set(r.lesson_id, s);
}
if (lessonStats.size === 0) {
  console.log('W_Regen Slack: no affected lessons — skipping notification');
  return [];
}

const messages = [];
for (const [lesson_id, { ok, failed }] of lessonStats) {
  const cellsLine = failed > 0 ? `${ok} (${failed} failed)` : `${ok}`;

  const lines = [
    ':arrows_counterclockwise: *Regen complete*',
    '',
    `*Lesson:* ${lesson_id}`,
    `*Cells regenerated:* ${cellsLine}`,
  ];
  if (fullUrl || segmentsUrl || vttUrl || regenUrl) lines.push('');
  if (fullUrl)     lines.push(`:file_folder: <${fullUrl}|Full audio (per-lang)>`);
  if (segmentsUrl) lines.push(`:musical_note: <${segmentsUrl}|Per-segment audio>`);
  if (vttUrl)      lines.push(`:closed_book: <${vttUrl}|VTT subtitles>`);
  if (regenUrl)    lines.push(`:wrench: <${regenUrl}|Regen Segments>`);

  messages.push({ json: { channel, text: lines.join('\n') } });
}
return messages;
